const body = $input.first().json;
const wishId = body.data.object.metadata.wish_id;
const paymentIntentId = body.data.object.payment_intent;
const customerEmail = body.data.object.customer_details?.email;

return [{ json: { wishId, paymentIntentId, customerEmail } }];

